const item = $input.first().json;
const sessionId = item.sessionId;
const chatInput = item.chatInput;

if (!$workflow.staticData.sessions) {
  $workflow.staticData.sessions = {};
}
if (!$workflow.staticData.sessions[sessionId]) {
  $workflow.staticData.sessions[sessionId] = { notebookInput: '', conversation: [] };
}

const session = $workflow.staticData.sessions[sessionId];

const isFirstMessage = session.conversation.length === 0;
if (isFirstMessage) {
  session.notebookInput = chatInput;
}

return [{ json: {
  sessionId,
  chatInput,
  notebookInput: session.notebookInput,
  conversation: session.conversation,
  isFirstMessage
} }];

const item = $input.first().json;
const trimmed = item.chatInput.trim();
const isDone = trimmed === '完成' || trimmed.toLowerCase() === 'done';
return [{ json: { ...item, isDone } }];

const item = $input.first().json;
const { chatInput, conversation } = item;

const systemPrompt = `你是一個知識萃取助理。使用者會貼上一段整理好的學習內容。
你的任務是幫助使用者萃取出有價值的問題。

流程：
1. 使用者貼上內容後，先簡短確認你理解了內容（1-2句）
2. 詢問使用者：「你在學習這個主題之前有什麼疑惑，或閱讀過程中冒出什麼問題？」
3. 使用者回答後繼續追問，直到他說沒有更多問題
4. 如果使用者說沒有想法，根據內容主動提出 3-5 個有深度的問題給他選擇或修改
5. 使用者輸入「完成」或「done」時，結束收集

語氣：簡潔、像組員討論，不要太正式。
語言：跟使用者一樣，預設繁體中文。`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...conversation,
  { role: 'user', content: chatInput }
];

return [{ json: { ...item, messages } }];

const prev = $('Build Chat Messages').first().json;
const assistantReply = $input.first().json.choices[0].message.content;

const { sessionId, chatInput, notebookInput, conversation } = prev;

const updatedConversation = [
  ...conversation,
  { role: 'user', content: chatInput },
  { role: 'assistant', content: assistantReply }
];

if (!$workflow.staticData.sessions) $workflow.staticData.sessions = {};
$workflow.staticData.sessions[sessionId] = {
  notebookInput,
  conversation: updatedConversation
};

return [{ json: { output: assistantReply } }];

const item = $input.first().json;
const { sessionId, notebookInput, conversation } = item;

const date = new Date().toISOString().split('T')[0];
const authorName = process.env.AUTHOR_NAME || 'Unknown';

const questionsUser = [];
const questionsModel = [];
for (let i = 2; i < conversation.length; i++) {
  const m = conversation[i];
  if (m.role === 'user') questionsUser.push(m.content);
}
for (const m of conversation) {
  if (m.role === 'assistant' && m.content.includes('？') && m.content.includes('\n')) {
    const lines = m.content.split('\n').filter(l => l.trim().endsWith('？'));
    questionsModel.push(...lines);
  }
}

const convText = conversation
  .map(m => `${m.role === 'user' ? '使用者' : '助理'}: ${m.content}`)
  .join('\n\n');

const prompt = `根據以下對話記錄，整理成指定的 markdown 格式。

對話記錄：
${convText}

輸出格式（只輸出 markdown，不要加任何說明文字）：
---
title: [從內容萃取主題標題，不超過 20 字]
date: ${date}
author: ${authorName}
source: [如果使用者有提到來源則填入，否則留空]
tags: [從內容萃取 3-5 個繁體中文關鍵字，逗號分隔]
---

## 摘要
[NotebookLM input 的核心重點，3-5 句話]

## 我的問題
[使用者自己提出的問題，條列式]

## 模型補充問題
[由模型主動提出的問題，條列式，若無則省略此區塊]`;

return [{ json: {
  sessionId,
  notebookInput,
  conversation,
  questionsUser,
  questionsModel,
  date,
  authorName,
  messages: [{ role: 'user', content: prompt }]
} }];

const fs = require('fs');
const path = require('path');

const prev = $('Build Summary Prompt').first().json;
const markdownContent = $input.first().json.choices[0].message.content;

const { sessionId, notebookInput, conversation, questionsUser, questionsModel, date, authorName } = prev;

const titleMatch = markdownContent.match(/^title:\s*(.+)$/m);
const rawTitle = titleMatch ? titleMatch[1].trim() : `note-${date}`;
const safeTitle = rawTitle.replace(/[\[\]\\/:*?"<>|]/g, '-').replace(/\s+/g, '-');

const yyyymm = date.slice(0, 7);

const mdDir = path.join('/vault/notes', yyyymm);
const rawDir = path.join('/vault/raw', yyyymm);

fs.mkdirSync(mdDir, { recursive: true });
fs.mkdirSync(rawDir, { recursive: true });

const mdPath = path.join(mdDir, safeTitle + '.md');
const rawPath = path.join(rawDir, safeTitle + '.json');

const rawData = {
  date,
  author: authorName,
  input: notebookInput,
  conversation,
  questions_by_user: questionsUser,
  questions_by_model: questionsModel
};

fs.writeFileSync(mdPath, markdownContent, 'utf8');
fs.writeFileSync(rawPath, JSON.stringify(rawData, null, 2), 'utf8');

if ($workflow.staticData.sessions) {
  delete $workflow.staticData.sessions[sessionId];
}

return [{ json: { output: `筆記已儲存！\n\n📄 ${mdPath}\n📦 ${rawPath}` } }];
